/**
 * Configuration module for Voynich transition visualizer.
 * 
 * Transcription config (char ordering, display mappings, etc.) is loaded from
 * docs/output/transcription_config.json - the single source of truth generated by
 * the Python processing scripts.
 * 
 * This file contains only presentation/viz-specific settings (color scales, defaults).
 */

const Config = (function() {
  
  // These will be populated from transcription_config.json
  let CHAR_DISPLAY = {};
  let BOUNDARY_DISPLAY = {};
  let BOUNDARY_TOOLTIPS = {};
  let BOUNDARY_CHARS = new Set();
  let CHAR_ORDER = [];
  let AGGREGATION_DEFINITIONS = {};
  let _configLoaded = false;
  
  /**
   * Load transcription config from JSON (called by DataLoader on init).
   * @param {Object} config - Config object from transcription_config.json
   */
  function loadTranscriptionConfig(config) {
    // Character display mappings
    CHAR_DISPLAY = config.char_display || {};
    
    // Boundary tokens
    if (config.boundary_tokens) {
      BOUNDARY_CHARS = new Set(Object.keys(config.boundary_tokens));
      BOUNDARY_DISPLAY = {};
      BOUNDARY_TOOLTIPS = {};
      for (const [token, info] of Object.entries(config.boundary_tokens)) {
        BOUNDARY_DISPLAY[token] = info.short;
        BOUNDARY_TOOLTIPS[token] = info.name;
      }
    }
    
    // Character ordering (with boundaries)
    CHAR_ORDER = config.char_order_with_boundaries || config.char_order || [];
    
    // Aggregation definitions
    AGGREGATION_DEFINITIONS = config.aggregations || {};
    
    _configLoaded = true;
  }
  
  /**
   * Check if config has been loaded.
   */
  function isConfigLoaded() {
    return _configLoaded;
  }
  
  // Color scales for heatmap
  const COLOR_SCALES = {
    // Blue to red sequential
    blueRed: {
      name: 'Blue-Red',
      stops: [
        { pos: 0.0, color: [248, 248, 255] },   // Ghost white
        { pos: 0.2, color: [198, 219, 239] },   // Light blue
        { pos: 0.4, color: [107, 174, 214] },   // Blue
        { pos: 0.6, color: [253, 141, 60] },    // Orange
        { pos: 0.8, color: [227, 74, 51] },     // Red-orange
        { pos: 1.0, color: [179, 0, 0] },       // Dark red
      ],
    },
    // Viridis-like
    viridis: {
      name: 'Viridis',
      stops: [
        { pos: 0.0, color: [253, 231, 37] },    // Yellow
        { pos: 0.25, color: [94, 201, 98] },    // Green
        { pos: 0.5, color: [33, 145, 140] },    // Teal
        { pos: 0.75, color: [59, 82, 139] },    // Blue
        { pos: 1.0, color: [68, 1, 84] },       // Purple
      ],
    },
    // Simple grayscale
    grayscale: {
      name: 'Grayscale',
      stops: [
        { pos: 0.0, color: [255, 255, 255] },
        { pos: 1.0, color: [20, 20, 20] },
      ],
    },
    // Heat (white-yellow-red)
    heat: {
      name: 'Heat',
      stops: [
        { pos: 0.0, color: [255, 255, 255] },   // White
        { pos: 0.3, color: [255, 255, 178] },   // Light yellow
        { pos: 0.5, color: [254, 204, 92] },    // Yellow
        { pos: 0.7, color: [253, 141, 60] },    // Orange
        { pos: 0.85, color: [240, 59, 32] },    // Red
        { pos: 1.0, color: [189, 0, 38] },      // Dark red
      ],
    },
  };
  
  // Diverging color scale for diff mode (blue = B higher, white = same, red = A higher)
  const DIFF_COLOR_SCALE = {
    name: 'Diverging (Blue-White-Red)',
    stops: [
      { pos: 0.0, color: [33, 102, 172] },    // Strong blue (B much higher)
      { pos: 0.25, color: [103, 169, 207] },  // Medium blue
      { pos: 0.45, color: [209, 229, 240] },  // Light blue
      { pos: 0.5, color: [247, 247, 247] },   // White/neutral (same)
      { pos: 0.55, color: [253, 219, 199] },  // Light red
      { pos: 0.75, color: [239, 138, 98] },   // Medium red
      { pos: 1.0, color: [178, 24, 43] },     // Strong red (A much higher)
    ],
  };
  
  // Default settings
  const DEFAULTS = {
    aggregation: 'all',
    displayMode: 'probabilities',  // 'probabilities' or 'counts'
    useVoynichFont: true,  // Default to Voynich font on
    showBoundaries: true,
    colorScale: 'viridis',
    useLogScale: false,
    cellSize: 28,  // Larger cells for better readability
    labelSize: 14,
    fontSize: 14,  // Larger font for labels
  };
  
  /**
   * Get display label for a character.
   * @param {string} char - Internal character code
   * @param {boolean} useVoynichFont - If true, return raw char for font rendering
   * @param {boolean} short - If true, return short version for boundaries
   * @returns {string} Display label
   */
  function getCharDisplay(char, useVoynichFont = false, short = true) {
    if (useVoynichFont && !BOUNDARY_CHARS.has(char)) {
      // For Voynich font, return the raw character
      // But expand numbers back to repeated i/e for font
      const fontMap = {
        '1': 'i', '2': 'ii', '3': 'iii', '4': 'iiii',
        '6': 'e', '7': 'ee', '8': 'eee', '9': 'eeee',
        'C': 'ch', 'S': 'sh', 'T': 'cth', 'P': 'cph', 'F': 'cfh', 'K': 'ckh',
      };
      return fontMap[char] || char;
    }
    
    // Check boundaries first
    if (BOUNDARY_CHARS.has(char)) {
      return short ? BOUNDARY_DISPLAY[char] : BOUNDARY_TOOLTIPS[char];
    }
    
    // Check display mappings
    if (CHAR_DISPLAY[char]) {
      return CHAR_DISPLAY[char];
    }
    
    return char;
  }
  
  /**
   * Get full tooltip text for a character.
   * @param {string} char - Internal character code
   * @returns {string} Tooltip text
   */
  function getCharTooltip(char) {
    if (BOUNDARY_CHARS.has(char)) {
      return BOUNDARY_TOOLTIPS[char];
    }
    if (CHAR_DISPLAY[char]) {
      return CHAR_DISPLAY[char];
    }
    return char;
  }
  
  /**
   * Check if a character is a boundary token.
   * @param {string} char - Character to check
   * @returns {boolean}
   */
  function isBoundaryChar(char) {
    return BOUNDARY_CHARS.has(char);
  }
  
  /**
   * Sort characters according to preferred order.
   * @param {string[]} chars - Array of characters
   * @returns {string[]} Sorted array
   */
  function sortCharacters(chars) {
    const orderMap = new Map(CHAR_ORDER.map((c, i) => [c, i]));
    return [...chars].sort((a, b) => {
      const aIdx = orderMap.has(a) ? orderMap.get(a) : 999;
      const bIdx = orderMap.has(b) ? orderMap.get(b) : 999;
      return aIdx - bIdx;
    });
  }
  
  /**
   * Interpolate between color stops to get color for a value.
   * @param {number} value - Value between 0 and 1
   * @param {string} scaleName - Name of color scale to use
   * @returns {string} CSS rgb() color string
   */
  function getColor(value, scaleName = 'heat') {
    const scale = COLOR_SCALES[scaleName] || COLOR_SCALES.heat;
    const stops = scale.stops;
    
    // Clamp value
    value = Math.max(0, Math.min(1, value));
    
    // Find surrounding stops
    let lower = stops[0];
    let upper = stops[stops.length - 1];
    
    for (let i = 0; i < stops.length - 1; i++) {
      if (value >= stops[i].pos && value <= stops[i + 1].pos) {
        lower = stops[i];
        upper = stops[i + 1];
        break;
      }
    }
    
    // Interpolate
    const range = upper.pos - lower.pos;
    const t = range > 0 ? (value - lower.pos) / range : 0;
    
    const r = Math.round(lower.color[0] + t * (upper.color[0] - lower.color[0]));
    const g = Math.round(lower.color[1] + t * (upper.color[1] - lower.color[1]));
    const b = Math.round(lower.color[2] + t * (upper.color[2] - lower.color[2]));
    
    return `rgb(${r}, ${g}, ${b})`;
  }
  
  /**
   * Get contrasting text color (black or white) for a background.
   * @param {number} value - Value between 0 and 1 (brightness proxy)
   * @returns {string} 'black' or 'white'
   */
  function getContrastColor(value) {
    return value > 0.5 ? 'white' : 'black';
  }
  
  /**
   * Apply logarithmic scaling to a value.
   * @param {number} value - Raw value
   * @param {number} max - Maximum value for normalization
   * @returns {number} Scaled value between 0 and 1
   */
  function logScale(value, max) {
    if (value <= 0 || max <= 0) return 0;
    return Math.log1p(value) / Math.log1p(max);
  }
  
  /**
   * Get color for diff mode (diverging scale).
   * Value should be normalized between -1 and 1, mapped to 0-1 for the scale.
   * @param {number} value - Normalized diff value (-1 to 1)
   * @returns {string} CSS rgb() color string
   */
  function getDiffColor(value) {
    const normalized = (value + 1) / 2;
    const stops = DIFF_COLOR_SCALE.stops;
    const clampedValue = Math.max(0, Math.min(1, normalized));
    
    let lower = stops[0];
    let upper = stops[stops.length - 1];
    
    for (let i = 0; i < stops.length - 1; i++) {
      if (clampedValue >= stops[i].pos && clampedValue <= stops[i + 1].pos) {
        lower = stops[i];
        upper = stops[i + 1];
        break;
      }
    }
    
    const range = upper.pos - lower.pos;
    const t = range > 0 ? (clampedValue - lower.pos) / range : 0;
    
    const r = Math.round(lower.color[0] + t * (upper.color[0] - lower.color[0]));
    const g = Math.round(lower.color[1] + t * (upper.color[1] - lower.color[1]));
    const b = Math.round(lower.color[2] + t * (upper.color[2] - lower.color[2]));
    
    return `rgb(${r}, ${g}, ${b})`;
  }
  
  /**
   * Get aggregation description.
   * @param {string} name - Aggregation name
   * @returns {string} Description or name if not found
   */
  function getAggregationDescription(name) {
    if (AGGREGATION_DEFINITIONS[name]) {
      return AGGREGATION_DEFINITIONS[name].description;
    }
    return name;
  }
  
  // Public API
  return {
    // Loaded from transcription config
    get CHAR_DISPLAY() { return CHAR_DISPLAY; },
    get BOUNDARY_DISPLAY() { return BOUNDARY_DISPLAY; },
    get BOUNDARY_TOOLTIPS() { return BOUNDARY_TOOLTIPS; },
    get BOUNDARY_CHARS() { return BOUNDARY_CHARS; },
    get CHAR_ORDER() { return CHAR_ORDER; },
    get AGGREGATION_DEFINITIONS() { return AGGREGATION_DEFINITIONS; },
    // Presentation config (static)
    COLOR_SCALES,
    DIFF_COLOR_SCALE,
    DEFAULTS,
    // Functions
    loadTranscriptionConfig,
    isConfigLoaded,
    getCharDisplay,
    getCharTooltip,
    isBoundaryChar,
    sortCharacters,
    getColor,
    getDiffColor,
    getContrastColor,
    logScale,
    getAggregationDescription,
  };
})();
